import java.util.Objects;

class User {
    private final int id;
    private String name;

    public User(int id, String name) {
        this.id = id;
        this.name = name;
    }

    @Override
    public boolean equals(Object other) {
        if (this == other) return true;
        if (!(other instanceof User)) return false;
        User u = (User) other;
        return this.id == u.id;
    }

    @Override
    public int hashCode() {
        return Objects.hash(id);
    }
}

public class App {
    public static void main(String[] args) {
        User[] users = {
            new User(1, "Aisha"),
            new User(2, "Raj"),
            new User(1, "Aisha"),
            new User(3, "Priya"),
            new User(2, "Raj"),
            new User(4, "Vikram")
        };

        System.out.println("Unique count: " + countUnique(users));
    }

    public static int countUnique(User[] users) {
        int count = 0;
        for (int i = 0; i < users.length; i++) {
            boolean isDuplicate = false;
            for (int j = 0; j < i; j++) {
                if (users[i].equals(users[j])) {
                    isDuplicate = true;
                    break;
                }
            }
            if (!isDuplicate) count++;
        }
        return count;
    }
}

