import java.util.Objects;

class Address {
    private String street;
    private String city;
    private String zip;

    public Address(String street, String city, String zip) {
        this.street = street;
        this.city = city;
        this.zip = zip;
    }

    @Override
    public String toString() {
        return "Address[" + street + ", " + city + ", " + zip + "]";
    }

    @Override
    public boolean equals(Object other) {
        if (this == other) return true;
        if (!(other instanceof Address)) return false;
        Address a = (Address) other;
        return Objects.equals(street, a.street)
            && Objects.equals(city, a.city)
            && Objects.equals(zip, a.zip);
    }

    @Override
    public int hashCode() {
        return Objects.hash(street, city, zip);
    }
}

class Person {
    private String name;
    private Address address;

    public Person(String name, Address address) {
        this.name = name;
        this.address = address;
    }

    @Override
    public String toString() {
        return "Person[name=" + name + ", address=" + address + "]";
    }

    @Override
    public boolean equals(Object other) {
        if (this == other) return true;
        if (!(other instanceof Person)) return false;
        Person p = (Person) other;
        return Objects.equals(name, p.name)
            && Objects.equals(address, p.address);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, address);
    }
}

public class App {
    public static void main(String[] args) {
        Address addr1 = new Address("123 MG Road", "Hyderabad", "500001");
        Address addr2 = new Address("123 MG Road", "Hyderabad", "500001");
        Address addr3 = new Address("456 Park Lane", "Mumbai", "400001");

        Person p1 = new Person("Aisha", addr1);
        Person p2 = new Person("Aisha", addr2);
        Person p3 = new Person("Aisha", addr3);

        System.out.println(p1);
        System.out.println("p1.equals(p2): " + p1.equals(p2));
        System.out.println("Same hashCode: " + (p1.hashCode() == p2.hashCode()));
        System.out.println("p1.equals(p3): " + p1.equals(p3));
    }
}
